12→/**
13→ * Validate an email address that the user wants to add to an account.
14→ *
15→ * This only allows a subset of all valid email addresses. We currently don't support international email addresses
16→ * and don't allow quoted local parts, or email addresses exceeding length restrictions.
17→ *
18→ * Note: Do NOT use this to validate recipients in incoming or outgoing messages. Use [String.toEmailAddressOrNull]
19→ * instead.
20→ */
21→class ValidateEmailAddress : UseCase.ValidateEmailAddress {
22→
23→    override fun execute(emailAddress: String): ValidationResult {
24→        if (emailAddress.isBlank()) {
25→            return ValidationResult.Failure(ValidateEmailAddressError.EmptyEmailAddress)
26→        }
27→
28→        return try {
29→            val parsedEmailAddress = emailAddress.toUserEmailAddress()
30→
31→            if (parsedEmailAddress.warnings.isEmpty()) {
32→                ValidationResult.Success
33→            } else {
34→                ValidationResult.Failure(ValidateEmailAddressError.NotAllowed)
35→            }
36→        } catch (e: EmailAddressParserException) {
37→            Timber.v(e, "Error parsing email address: %s", emailAddress)
38→
39→            val validationError = when (e.error) {
40→                EmailAddressParserError.AddressLiteralsNotSupported,
41→                EmailAddressParserError.LocalPartLengthExceeded,
42→                EmailAddressParserError.DnsLabelLengthExceeded,
43→                EmailAddressParserError.DomainLengthExceeded,
44→                EmailAddressParserError.TotalLengthExceeded,
45→                EmailAddressParserError.QuotedStringInLocalPart,
46→                EmailAddressParserError.LocalPartRequiresQuotedString,
47→                EmailAddressParserError.EmptyLocalPart,
48→                -> {
49→                    ValidateEmailAddressError.NotAllowed
50→                }
51→
52→                else -> {
53→                    if ('@' in emailAddress) {
54→                        // We currently don't support or recognize international email addresses. So if the string
55→                        // contains an "@" character, we assume it's a valid email address that we don't support.
56→                        ValidateEmailAddressError.InvalidOrNotSupported
57→                    } else {
58→                        ValidateEmailAddressError.InvalidEmailAddress
59→                    }
60→                }
61→            }
62→
63→            ValidationResult.Failure(validationError)
64→        }
65→    }
66→
67→    sealed interface ValidateEmailAddressError : ValidationError {
68→        data object EmptyEmailAddress : ValidateEmailAddressError
69→        data object NotAllowed : ValidateEmailAddressError
70→        data object InvalidOrNotSupported : ValidateEmailAddressError
71→        data object InvalidEmailAddress : ValidateEmailAddressError
72→    }
73→}
