 7→// See RFC 1035, 2.3.4.
 8→// For the string representation used in emails (labels separated by dots, no final dot allowed), we end up with a
 9→// maximum of 253 characters.
10→internal const val MAXIMUM_DOMAIN_LENGTH = 253
11→
12→// See RFC 1035, 2.3.4.
13→internal const val MAXIMUM_DNS_LABEL_LENGTH = 63
14→
15→/**
16→ * Parser for domain names in email addresses.
17→ *
18→ * From RFC 5321:
19→ * ```
20→ * Domain                  = sub-domain *("." sub-domain)
21→ * sub-domain              = Let-dig [Ldh-str]
22→ * Let-dig                 = ALPHA / DIGIT
23→ * Ldh-str                 = *( ALPHA / DIGIT / "-" ) Let-dig
24→ * ```
25→ */
26→internal class EmailDomainParser(
27→    input: String,
28→    startIndex: Int = 0,
29→    endIndex: Int = input.length,
30→) : AbstractParser(input, startIndex, endIndex) {
31→
32→    fun parseDomain(): EmailDomain {
33→        val domain = readDomain()
34→
35→        if (!endReached()) {
36→            parserError(ExpectedEndOfInput)
37→        }
38→
39→        return domain
40→    }
41→
42→    fun readDomain(): EmailDomain {
43→        val domain = readString {
44→            expectSubDomain()
45→
46→            while (!endReached() && peek() == DOT) {
47→                expect(DOT)
48→                expectSubDomain()
49→            }
50→        }
51→
52→        if (domain.length > MAXIMUM_DOMAIN_LENGTH) {
53→            parserError(DomainLengthExceeded)
54→        }
55→
56→        return EmailDomain(domain)
57→    }
58→
59→    private fun expectSubDomain() {
60→        val startIndex = currentIndex
61→
62→        expectLetDig()
63→
64→        var requireLetDig = false
65→        while (!endReached()) {
66→            val character = peek()
67→            when {
68→                character == HYPHEN -> {
69→                    requireLetDig = true
70→                    expect(HYPHEN)
71→                }
72→                character.isLetDig -> {
73→                    requireLetDig = false
74→                    expectLetDig()
75→                }
76→                else -> break
77→            }
78→        }
79→
80→        if (requireLetDig) {
81→            expectLetDig()
82→        }
83→
84→        if (currentIndex - startIndex > MAXIMUM_DNS_LABEL_LENGTH) {
85→            parserError(DnsLabelLengthExceeded)
86→        }
87→    }
88→
89→    private fun expectLetDig() {
90→        expect("'Let-dig'") { it.isLetDig }
91→    }
92→}
